tility-first elimina los problemas de especificidad de CSS, facilita la revisión de estilos en Code Review y garantiza la consistencia visual a través de tokens predefinidos. La personalización del tema debe realizarse exclusivamente en `tailwind.config.ts`, donde se definen los to diseño del proyecto. ```typescript

// tailwind.config.ts import type { Config } from 'tailwindcss'; const config: Config = { content: ['./src/*/.{ts,tsx}'], theme: { extend: { colors: { brand: { 50:  '#f0f4ff', 500: '#3b5bdb', 900: '#1a237e', }, neutral: { 50:  '#f8f9fa', 500: '#868e96', 900: '#212529', }, success: '#2f9e44', warning: '#f59f00', error:   '#e03131', }, fontFamily: { sans: ['Inter', 'system-ui', 'sans-serif'], mono: ['JetBrains Mono', 'monospace'], }, spacing: { '4.5': '1.125rem', '18':  '4.5rem', }, }, }, plugins: [require('tailwindcss-animate')], }; export default config; ``` 8.2 shadcn/ui como Biblioteca de Componentes Base

